// Cross-runtime ORT session contract test.
//
// Reads tests/fixtures/ort_session/contract.json (regenerated by
// scripts/regenerate_ort_session_fixture.py from
// docs/spec/ort-session-contract.toml) and asserts that the C++
// implementation in src/cpp/piper.cpp uses the same canonical values
// that the other runtimes (Python, Rust, Go, C#) match.
//
// Self-contained: re-declares the constants identically to piper.cpp so
// the test does not require linking the production library. Mirrors the
// pattern in test_short_text_contract.cpp.
//
// Production constants (must stay in sync with piper.cpp):
//   - MAX_INTRA_THREADS = 4              (piper.cpp:78)
//   - dynamic_block_base = "4"           (piper.cpp:514, AddConfigEntry)
//   - SetGraphOptimizationLevel(ORT_ENABLE_ALL) (piper.cpp:500)
//   - SetExecutionMode(ORT_SEQUENTIAL)   (piper.cpp:510)
//   - SetInterOpNumThreads(1)            (piper.cpp:511)
//   - warmup phonemeLength = 100         (piper.cpp:2967)
//   - warmup BOS = 1, EOS = 2, dummy = 8 (piper.cpp:2970-2972)
//   - warmup default runs = 2            (piper.cpp:warmupModel(...) sig in piper.h)
//   - warmup scales: noise=0.4, length=1.0, w=0.5 (piper.cpp:2973 + config defaults
//     at piper.cpp:264/272 for SynthesisConfig; v1.12.0 で全 runtime 統一)
//
// The C++ runtime does NOT implement model-cache (.opt.onnx[.ok]) nor the
// PIPER_DISABLE_WARMUP / PIPER_DISABLE_CACHE / PIPER_INTRA_THREADS env
// vars; those rows are pinned to the fixture for forward-compat drift
// detection only. See docs/spec/ort-session-contract.toml [env_vars.implementation_status].

#include <gtest/gtest.h>

#include <cstdint>
#include <cstdlib>
#include <filesystem>
#include <fstream>
#include <sstream>
#include <string>

#include "json.hpp"

namespace {

namespace fs = std::filesystem;
using nlohmann::json;

// ---------------------------------------------------------------------------
// Re-declare the production constants identically to src/cpp/piper.cpp so the
// tests are self-contained (no piper.cpp linkage required). If piper.cpp's
// values drift from the contract, this test must fail.
// ---------------------------------------------------------------------------

namespace cpp_constants {
// piper.cpp:78
constexpr int MAX_INTRA_THREADS = 4;
// piper.cpp:514: session.options.AddConfigEntry("session.dynamic_block_base", "4");
constexpr int DYNAMIC_BLOCK_BASE = 4;
// piper.cpp:511: session.options.SetInterOpNumThreads(1);
constexpr int INTER_OP_THREADS = 1;
// piper.cpp:2967
constexpr int WARMUP_PHONEME_LENGTH = 100;
// piper.cpp:2970-2972: BOS, dummy, EOS tokens.
constexpr int WARMUP_BOS_TOKEN = 1;
constexpr int WARMUP_EOS_TOKEN = 2;
constexpr int WARMUP_DUMMY_PHONEME = 8;
// main.cpp:294 — `piper::warmupModel(voice.session)` defaults to 2 runs
// (piper.h: void warmupModel(ModelSession &, int runs = 2);).
constexpr int WARMUP_DEFAULT_RUNS = 2;
// piper.cpp:264/272: SynthesisConfig defaults pulled into warmup at line 2973.
// v1.12.0 で全 runtime canonical 0.4/1.0/0.5 に統一済 (contract.json と整合)。
constexpr float WARMUP_NOISE_SCALE = 0.4f;
constexpr float WARMUP_LENGTH_SCALE = 1.0f;
constexpr float WARMUP_NOISE_W = 0.5f;
}  // namespace cpp_constants

// ---------------------------------------------------------------------------
// Fixture loading (mirrors test_short_text_contract.cpp / test_phoneme_timing_parity.cpp)
// ---------------------------------------------------------------------------

fs::path findFixturePath() {
  if (const char* env = std::getenv("PIPER_ORT_SESSION_FIXTURE")) {
    return fs::path(env);
  }

  const fs::path needle =
      fs::path("tests") / "fixtures" / "ort_session" / "contract.json";
  fs::path cwd = fs::current_path();
  for (int depth = 0; depth < 8; ++depth) {
    fs::path candidate = cwd / needle;
    if (fs::exists(candidate)) {
      return candidate;
    }
    if (!cwd.has_parent_path() || cwd == cwd.parent_path()) {
      break;
    }
    cwd = cwd.parent_path();
  }
  return needle;  // last resort — will fail open + give a useful error
}

json loadFixture() {
  const fs::path fixture_path = findFixturePath();
  std::ifstream stream(fixture_path);
  EXPECT_TRUE(stream.is_open())
      << "Cannot open ORT session contract fixture: " << fixture_path
      << " (cwd=" << fs::current_path()
      << "). Set PIPER_ORT_SESSION_FIXTURE if the default search path doesn't "
         "apply.";
  std::stringstream buffer;
  buffer << stream.rdbuf();
  return json::parse(buffer.str());
}

}  // namespace

// ---------------------------------------------------------------------------
// 1. Fixture sanity
// ---------------------------------------------------------------------------

TEST(OrtSessionContract, FixtureLoadsAndIsSchemaV1) {
  const auto fixture = loadFixture();
  ASSERT_TRUE(fixture.contains("schema_version"));
  EXPECT_EQ(fixture["schema_version"].get<int>(), 1);

  ASSERT_TRUE(fixture.contains("session"));
  ASSERT_TRUE(fixture.contains("warmup"));
  ASSERT_TRUE(fixture.contains("cache"));
  ASSERT_TRUE(fixture.contains("env_vars"));
}

