// 2. Session constants
// ---------------------------------------------------------------------------

TEST(OrtSessionContract, Session_GraphOptimizationLevel) {
  const auto fixture = loadFixture();
  // piper.cpp:500-501:
  //   session.options.SetGraphOptimizationLevel(
  //       GraphOptimizationLevel::ORT_ENABLE_ALL);
  EXPECT_EQ(fixture["session"]["graph_optimization_level"].get<std::string>(),
            "ORT_ENABLE_ALL");
}

TEST(OrtSessionContract, Session_ExecutionMode) {
  const auto fixture = loadFixture();
  // piper.cpp:510:
  //   session.options.SetExecutionMode(ExecutionMode::ORT_SEQUENTIAL);
  EXPECT_EQ(fixture["session"]["execution_mode"].get<std::string>(),
            "SEQUENTIAL");
}

TEST(OrtSessionContract, Session_MaxIntraThreads) {
  const auto fixture = loadFixture();
  EXPECT_EQ(cpp_constants::MAX_INTRA_THREADS,
            fixture["session"]["max_intra_threads"].get<int>());
}

TEST(OrtSessionContract, Session_InterOpThreads) {
  const auto fixture = loadFixture();
  EXPECT_EQ(cpp_constants::INTER_OP_THREADS,
            fixture["session"]["inter_op_threads"].get<int>());
}

TEST(OrtSessionContract, Session_DynamicBlockBase) {
  const auto fixture = loadFixture();
  EXPECT_EQ(cpp_constants::DYNAMIC_BLOCK_BASE,
            fixture["session"]["dynamic_block_base"].get<int>());
}

TEST(OrtSessionContract, Session_EnableCpuMemArena_FixtureValue) {
  const auto fixture = loadFixture();
  // piper.cpp:503-507 documents that CPU memory arena and memory pattern are
  // left at the ORT defaults (i.e. enabled). We don't call DisableCpuMemArena()
  // anywhere in piper.cpp, so contract value `true` is preserved.
  EXPECT_TRUE(fixture["session"]["enable_cpu_mem_arena"].get<bool>());
}

TEST(OrtSessionContract, Session_EnableMemoryPattern_FixtureValue) {
  const auto fixture = loadFixture();
  // piper.cpp:503-507: ORT default is enabled, no DisableMemPattern() call.
  EXPECT_TRUE(fixture["session"]["enable_memory_pattern"].get<bool>());
}

