// ---------------------------------------------------------------------------
// 4. Cache constants — NOT implemented in C++.
//
// piper.cpp does not read or write `.opt.onnx` / `.opt.onnx.ok` artifacts;
// the optimised-model cache lives in the Python runtime only (see
// src/python/piper_train/ort_utils.py). We still pin the fixture values
// so the C++ runtime catches any contract-side rename and consciously
// decides whether to implement caching.
// ---------------------------------------------------------------------------

TEST(OrtSessionContract, Cache_OptimizedExtension_FixtureValue) {
  const auto fixture = loadFixture();
  EXPECT_EQ(fixture["cache"]["optimized_extension"].get<std::string>(),
            "opt.onnx");
}

