TEST(OrtSessionContract, EnvVars_IntraThreads_FixtureValue) {
  const auto fixture = loadFixture();
  EXPECT_EQ(fixture["env_vars"]["intra_threads"].get<std::string>(),
            "PIPER_INTRA_THREADS");
}
